#include <iostream>

class BankAccount {
private:
    double balance;
public:
    BankAccount(double initial) : balance(initial) {}

    void deposit(double amount) {
        balance += amount;
    }

    double getBalance() {
        return balance;
    }
};

int main() {
    BankAccount myAcc(500.0);
    myAcc.deposit(250.0);
    std::cout << "Final Balance: " << myAcc.getBalance() << std::endl;
    return 0;
}
